import React, { useState } from "react";

export default function CreateParticipant({ onSubmit }) {
  const [formData, setFormData] = useState({
    cosplayName: "",
    character: "",
    game: "",
    characterImage: null,
    cosplayImages: [],
    wipImages: []
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleFileChange = (e, field, multiple = false) => {
    const files = multiple ? Array.from(e.target.files) : e.target.files[0];
    setFormData({ ...formData, [field]: files });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // FormData für Bilder + Textfelder
    const data = new FormData();
    data.append("cosplayName", formData.cosplayName);
    data.append("character", formData.character);
    data.append("game", formData.game);
    if (formData.characterImage) {
      data.append("characterImage", formData.characterImage);
    }
    formData.cosplayImages.forEach((file, i) =>
      data.append(`cosplayImages`, file)
    );
    formData.wipImages.forEach((file, i) =>
      data.append(`wipImages`, file)
    );

    // Übergabe an Elternkomponente oder fetch-Aufruf
    onSubmit(data);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4 p-4 bg-white rounded-xl shadow-md">
      <div>
        <label className="block font-semibold">Cosplayname</label>
        <input
          type="text"
          name="cosplayName"
          className="border p-2 rounded w-full"
          value={formData.cosplayName}
          onChange={handleChange}
        />
      </div>
      <div>
        <label className="block font-semibold">Charakter</label>
        <input
          type="text"
          name="character"
          className="border p-2 rounded w-full"
          value={formData.character}
          onChange={handleChange}
        />
      </div>
      <div>
        <label className="block font-semibold">Game</label>
        <input
          type="text"
          name="game"
          className="border p-2 rounded w-full"
          value={formData.game}
          onChange={handleChange}
        />
      </div>
      <div>
        <label className="block font-semibold">Charakterbild</label>
        <input
          type="file"
          accept="image/*"
          onChange={(e) => handleFileChange(e, "characterImage")}
        />
      </div>
      <div>
        <label className="block font-semibold">Cosplaybilder</label>
        <input
          type="file"
          multiple
          accept="image/*"
          onChange={(e) => handleFileChange(e, "cosplayImages", true)}
        />
      </div>
      <div>
        <label className="block font-semibold">WIP Bilder</label>
        <input
          type="file"
          multiple
          accept="image/*"
          onChange={(e) => handleFileChange(e, "wipImages", true)}
        />
      </div>
      <button
        type="submit"
        className="bg-green-600 text-white px-4 py-2 rounded shadow"
      >
        Speichern
      </button>
    </form>
  );
}
